using System.Reflection;

var abstractions = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.agents.ai.abstractions/1.4.0/lib/net10.0/Microsoft.Agents.AI.Abstractions.dll");
var main = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.agents.ai/1.4.0/lib/net10.0/Microsoft.Agents.AI.dll");

foreach (var asm in new[] { abstractions, main })
{
    Console.WriteLine($"\n=== {asm.GetName().Name} ===");
    var types = asm.GetExportedTypes().OrderBy(t => t.FullName);
    foreach (var t in types)
    {
        var kind = t.IsClass ? "class" : t.IsInterface ? "interface" : t.IsEnum ? "enum" : "struct";
        Console.WriteLine($"\n{kind} {t.FullName}" + (t.BaseType != null && t.BaseType != typeof(object) ? $" : {t.BaseType.Name}" : ""));
        foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
            Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName).Take(10))
            Console.WriteLine($"  method {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
EOF
