using System.Reflection;
using Microsoft.Extensions.AI;

var meaiAsm = typeof(IChatClient).Assembly;
Console.WriteLine($"=== {meaiAsm.GetName().Name} v{meaiAsm.GetName().Version} ===");

// Focus on ChatOptions
var chatOptionsType = typeof(ChatOptions);
Console.WriteLine($"\nclass ChatOptions");
foreach (var p in chatOptionsType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");

// Focus on AIFunction
Console.WriteLine("\n--- AIFunctionFactory ---");
var factoryType = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "AIFunctionFactory");
if (factoryType != null)
{
    foreach (var m in factoryType.GetMethods(BindingFlags.Public | BindingFlags.Static).Take(15))
        Console.WriteLine($"  static {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

// AITool
Console.WriteLine("\n--- AITool ---");
var toolType = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "AITool");
if (toolType != null)
{
    foreach (var p in toolType.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
}

// AIFunction
Console.WriteLine("\n--- AIFunction ---");
var funcType = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "AIFunction");
if (funcType != null)
{
    foreach (var p in funcType.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
    foreach (var m in funcType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  method {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

// FunctionInvocationContext check
Console.WriteLine("\n--- FunctionInvokingChatClient ---");
var ficType = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "FunctionInvokingChatClient");
if (ficType != null)
{
    foreach (var c in ficType.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var p in ficType.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
}
EOF
