using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability for the research agent.
/// Replace the simulated results with a real search API (e.g., Bing Search) for production use.
/// </summary>
public sealed class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new();
    private readonly string? _searchApiKey;

    public WebSearchTool(string? searchApiKey = null)
    {
        _searchApiKey = searchApiKey;
    }

    [Description("Search the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        if (string.IsNullOrWhiteSpace(query))
            return [];

        maxResults = Math.Clamp(maxResults, 1, 10);

        // If a Bing Search API key is configured, use the real API
        if (!string.IsNullOrEmpty(_searchApiKey))
        {
            return await SearchWithBingAsync(query, maxResults, cancellationToken);
        }

        // Fallback: simulated search results for demonstration
        return GetSimulatedResults(query, maxResults);
    }

    private async Task<IReadOnlyList<SearchResult>> SearchWithBingAsync(
        string query, int maxResults, CancellationToken cancellationToken)
    {
        var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count={maxResults}");
        request.Headers.Add("Ocp-Apim-Subscription-Key", _searchApiKey);

        var response = await s_httpClient.SendAsync(request, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<BingSearchResponse>(cancellationToken: cancellationToken);
        return json?.WebPages?.Value?.Select(p => new SearchResult(p.Name, p.Snippet, p.Url)).ToList()
            ?? [];
    }

    private static List<SearchResult> GetSimulatedResults(string query, int maxResults)
    {
        // Simulated results that demonstrate the tool's interface
        var results = new List<SearchResult>
        {
            new($"Overview of {query}",
                $"{query} is a rapidly evolving field with significant developments in recent years. " +
                "Researchers have made breakthroughs in efficiency and scalability.",
                $"https://example.com/overview-{Uri.EscapeDataString(query.ToLowerInvariant().Replace(' ', '-'))}"),
            new($"Latest Research in {query}",
                $"A 2025 study published in Nature demonstrates new approaches to {query.ToLowerInvariant()} " +
                "that improve performance by 40% compared to previous methods.",
                $"https://example.com/research-{Uri.EscapeDataString(query.ToLowerInvariant().Replace(' ', '-'))}"),
            new($"{query}: Practical Applications",
                $"Industries ranging from healthcare to finance are adopting {query.ToLowerInvariant()} " +
                "solutions. Key applications include automation, prediction, and optimization.",
                $"https://example.com/applications-{Uri.EscapeDataString(query.ToLowerInvariant().Replace(' ', '-'))}"),
            new($"Challenges and Future of {query}",
                $"Despite progress, {query.ToLowerInvariant()} faces challenges including scalability, " +
                "ethical considerations, and integration with existing systems.",
                $"https://example.com/challenges-{Uri.EscapeDataString(query.ToLowerInvariant().Replace(' ', '-'))}"),
            new($"Expert Opinions on {query}",
                $"Leading experts predict that {query.ToLowerInvariant()} will transform how we approach " +
                "complex problems within the next decade.",
                $"https://example.com/experts-{Uri.EscapeDataString(query.ToLowerInvariant().Replace(' ', '-'))}"),
        };

        return results.Take(maxResults).ToList();
    }

    // DTOs for Bing API response
    private sealed record BingSearchResponse(BingWebPages? WebPages);
    private sealed record BingWebPages(List<BingWebPage>? Value);
    private sealed record BingWebPage(string Name, string Snippet, string Url);
}

public sealed record SearchResult(
    [property: Description("Title of the search result")] string Title,
    [property: Description("Brief snippet or summary of the content")] string Snippet,
    [property: Description("URL of the source")] string Url);

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability for the research agent to track findings during research.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    [Description("Save a research note with a title, content, and source URL. Use this to record key findings during research.")]
    public string AddNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The content or key finding to record")] string content,
        [Description("Source URL where this information was found")] string sourceUrl)
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(content))
            return "Error: Title and content are required.";

        var note = new ResearchNote(
            Id: _notes.Count + 1,
            Title: title.Trim(),
            Content: content.Trim(),
            SourceUrl: sourceUrl?.Trim() ?? "unknown",
            CreatedAt: DateTimeOffset.UtcNow);

        _notes.Add(note);
        return $"Note #{note.Id} saved: \"{note.Title}\"";
    }

    [Description("Retrieve all saved research notes. Returns the full list of notes taken during this research session.")]
    public IReadOnlyList<ResearchNote> GetAllNotes()
    {
        return _notes.AsReadOnly();
    }

    [Description("Search notes by keyword. Returns notes whose title or content contains the search term.")]
    public IReadOnlyList<ResearchNote> SearchNotes(
        [Description("Keyword to search for in note titles and content")] string keyword)
    {
        if (string.IsNullOrWhiteSpace(keyword))
