using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable. " +
        "Optionally set BING_SEARCH_API_KEY for real web search.");

var searchApiKey = Environment.GetEnvironmentVariable("BING_SEARCH_API_KEY");
var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Create the chat client via MEAI abstraction
var openAiClient = new OpenAIClient(apiKey);
IChatClient chatClient = openAiClient
    .GetChatClient(modelId)
    .AsIChatClient();

// Create tool instances
var webSearch = new WebSearchTool(searchApiKey);
var noteTaking = new NoteTakingTool();

// Register tools with the agent
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(noteTaking.AddNote),
    AIFunctionFactory.Create(noteTaking.GetAllNotes),
    AIFunctionFactory.Create(noteTaking.SearchNotes),
};

// Build the research agent with Microsoft Agent Framework
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = tools,
        },
    });

// Get the research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");
Console.WriteLine(new string('─', 60));

// Create a session and run the agent
var session = await agent.CreateSessionAsync();

var userMessage = new ChatMessage(ChatRole.User,
    $"""
    Research the following topic thoroughly: "{topic}"

    Instructions:
    1. Search the web for information about this topic using multiple queries
    2. Take notes on the most important findings (use the note-taking tool)
    3. After gathering enough information, retrieve all your notes
    4. Provide a comprehensive summary of your research findings

    Format your final summary with clear sections including:
    - Overview
    - Key Findings
    - Applications/Implications
    - Sources
    """);

// Stream the agent's response
await foreach (var update in agent.RunStreamingAsync(userMessage, session))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine($"\n\n{new string('─', 60)}");
Console.WriteLine($"📝 Research complete. {noteTaking.NoteCount} note(s) recorded.");

