+    return;
+}
+
+Console.WriteLine($"\n🔍 Researching: {topic}\n");
+Console.WriteLine(new string('─', 60));
+
+// Create a session and run the agent
+var session = await agent.CreateSessionAsync();
+
+var userMessage = new ChatMessage(ChatRole.User,
+    $"""
+    Research the following topic thoroughly: "{topic}"
+    
+    Instructions:
+    1. Search the web for information about this topic using multiple queries
+    2. Take notes on the most important findings (use the note-taking tool)
+    3. After gathering enough information, retrieve all your notes
+    4. Provide a comprehensive summary of your research findings
+    
+    Format your final summary with clear sections including:
+    - Overview
+    - Key Findings
+    - Applications/Implications
+    - Sources
+    """);
+
+// Stream the agent's response
+await foreach (var update in agent.RunStreamingAsync(userMessage, session))
+{
+    if (!string.IsNullOrEmpty(update.Text))
+    {
+        Console.Write(update.Text);
+    }
+}
+
+Console.WriteLine($"\n\n{new string('─', 60)}");
+Console.WriteLine($"📝 Research complete. {noteTaking.NoteCount} note(s) recorded.");

